export const MANUAL_HTML = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>YoSched — User Manual</title>\n<style>\n:root { color-scheme: dark; }\n* { box-sizing: border-box; }\nbody { margin: 0; background: #0f172a; color: #cbd5e1;\n  font: 16px/1.7 -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif; }\n.topbar { position: sticky; top: 0; z-index: 10; background: #0b1220ee; backdrop-filter: blur(6px);\n  border-bottom: 1px solid #334155; padding: 12px 24px; font-weight: 700; color: #e2e8f0; }\n.topbar span { color: #63b3ed; }\n.brand { color: #63b3ed; }\nmain { max-width: 860px; margin: 0 auto; padding: 32px 24px 96px; }\nh1, h2, h3, h4 { color: #f1f5f9; line-height: 1.25; scroll-margin-top: 64px; }\nh1 { font-size: 2rem; margin: 0 0 .5rem; }\nh2 { font-size: 1.5rem; margin: 2.5rem 0 1rem; padding-bottom: .3rem; border-bottom: 1px solid #334155; }\nh3 { font-size: 1.2rem; margin: 1.8rem 0 .6rem; color: #e2e8f0; }\nh4 { font-size: 1.02rem; margin: 1.3rem 0 .4rem; color: #cbd5e1; }\na { color: #63b3ed; text-decoration: none; }\na:hover { text-decoration: underline; }\n.anchor { margin-left: .4rem; color: #475569; opacity: 0; font-weight: 400; }\nh1:hover .anchor, h2:hover .anchor, h3:hover .anchor, h4:hover .anchor { opacity: 1; }\np { margin: .7rem 0; }\nul, ol { margin: .6rem 0; padding-left: 1.5rem; }\nli { margin: .25rem 0; }\nli > ul, li > ol { margin: .25rem 0; }\ncode { background: #1e293b; border: 1px solid #334155; border-radius: 4px; padding: .08em .35em;\n  font: .85em ui-monospace, SFMono-Regular, Menlo, monospace; color: #e2e8f0; }\nstrong { color: #f1f5f9; }\nhr { border: none; border-top: 1px solid #1e293b; margin: 2rem 0; }\nblockquote { margin: 1rem 0; padding: .6rem 1rem; background: #15213a;\n  border-left: 3px solid #3b82f6; border-radius: 0 6px 6px 0; color: #b6c2d4; }\nblockquote p { margin: 0; }\ntable { border-collapse: collapse; width: 100%; margin: 1rem 0; font-size: .92rem; display: block; overflow-x: auto; }\nth, td { border: 1px solid #334155; padding: .5rem .7rem; text-align: left; vertical-align: top; }\nth { background: #1e293b; color: #e2e8f0; font-weight: 600; }\ntr:nth-child(even) td { background: #131c30; }\n.totop { position: fixed; right: 20px; bottom: 20px; background: #1e293b; border: 1px solid #475569;\n  color: #cbd5e1; border-radius: 8px; padding: 8px 12px; font-size: .85rem; }\n.totop:hover { background: #334155; text-decoration: none; }\n</style>\n</head>\n<body>\n<div class=\"topbar\">Yo<span>Sched</span> — User Manual</div>\n<main><h1 id=\"yosched--user-manual\">Yo<span class=\"brand\">Sched</span> — User Manual<a class=\"anchor\" href=\"#yosched--user-manual\" aria-hidden=\"true\">#</a></h1><p><em>A complete guide to scheduling staff with YoSched.</em></p><hr><h2 id=\"table-of-contents\">Table of Contents<a class=\"anchor\" href=\"#table-of-contents\" aria-hidden=\"true\">#</a></h2><ol><li><a href=\"#1-introduction\">Introduction</a></li><li><a href=\"#2-core-concepts\">Core Concepts</a></li><li><a href=\"#3-getting-started\">Getting Started</a></li><li><a href=\"#4-roles--permissions\">Roles &amp; Permissions</a></li><li><a href=\"#5-the-schedule-grid\">The Schedule Grid</a></li><li><a href=\"#6-auto-generate\">Auto-Generate</a></li><li><a href=\"#7-requests\">Requests</a></li><li><a href=\"#8-staff-management\">Staff Management</a></li><li><a href=\"#9-statistics--equity\">Statistics &amp; Equity</a></li><li><a href=\"#10-settings\">Settings</a></li><li><a href=\"#11-user-management\">User Management</a></li><li><a href=\"#12-your-account\">Your Account</a></li><li><a href=\"#13-printing\">Printing</a></li><li><a href=\"#appendix-a--keyboard-shortcuts\">Appendix A — Keyboard Shortcuts</a></li><li><a href=\"#appendix-b--glossary\">Appendix B — Glossary</a></li><li><a href=\"#appendix-c--permission-reference\">Appendix C — Permission Reference</a></li></ol><hr><h2 id=\"1-introduction\">1. Introduction<a class=\"anchor\" href=\"#1-introduction\" aria-hidden=\"true\">#</a></h2><p>YoSched is a web application for building and managing staff work schedules for a department — particularly clinical/medical teams that juggle call shifts, coverage minimums, leave requests, and fairness across people.</p><p>It gives you:</p><ul><li>A <strong>spreadsheet-style schedule grid</strong> with click, keyboard, and drag editing.</li><li>An <strong>auto-generator</strong> that fills the schedule for you while respecting coverage rules, eligibility, requests, and hour targets — and lets you steer it interactively.</li><li>A <strong>request workflow</strong> so staff can ask for shifts or time off, and schedulers can review and approve them.</li><li><strong>Equity analytics</strong> that show, with charts and z-scores, whether undesirable work is being shared fairly.</li><li>Deep <strong>settings</strong> for shift types, staffing minimums, pay periods, holidays, desirability, and the scheduling engine's priorities.</li></ul><p>The app uses a dark theme throughout. Most screens save automatically or show a clear <strong>Save</strong> button with a \"Saving… / Saved / Error\" status.</p><hr><h2 id=\"2-core-concepts\">2. Core Concepts<a class=\"anchor\" href=\"#2-core-concepts\" aria-hidden=\"true\">#</a></h2><p>Understanding these terms makes the rest of the manual easier to follow.</p><table><thead><tr><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Staff member</strong></td><td>A person who can be scheduled. Identified by <strong>initials</strong> (a 2–4 character code shown on the grid).</td></tr><tr><td><strong>Shift type</strong></td><td>A code such as <code>CALL</code>, <code>ORC</code>, <code>ORL</code>, <code>ADM</code>, or a leave type. Each has hours, a color, and scheduling rules.</td></tr><tr><td><strong>Assignment</strong></td><td>One staff member working one shift on one day (a single cell on the grid).</td></tr><tr><td><strong>Pay period</strong></td><td>A 14-day biweekly window. Hours are totaled and compared to targets per pay period.</td></tr><tr><td><strong>FTE</strong></td><td>Full-Time Equivalent. A 1.0 FTE works the full pay-period hours target (e.g., 80); a 0.5 FTE targets half.</td></tr><tr><td><strong>Coverage / staffing requirement</strong></td><td>The minimum number of staff that must work a given shift on a given day.</td></tr><tr><td><strong>Eligibility</strong></td><td>Whether a staff member is qualified/allowed to work a given shift.</td></tr><tr><td><strong>Availability</strong></td><td>The days/patterns a staff member is willing or able to work.</td></tr><tr><td><strong>Request</strong></td><td>A staff member's wish to work — or avoid — certain shifts on certain dates.</td></tr><tr><td><strong>Equity / desirability</strong></td><td>A fairness measure of how much undesirable work each person carries.</td></tr><tr><td><strong>Source</strong></td><td>Where an assignment came from: <strong>Manual</strong> (hand-placed), <strong>Auto</strong> (auto-generated), <strong>Imported</strong>, or <strong>Request-placed</strong>.</td></tr><tr><td><strong>Lock</strong></td><td>A flag that protects an assignment from being changed by the auto-generator or accidental edits.</td></tr></tbody></table><hr><h2 id=\"3-getting-started\">3. Getting Started<a class=\"anchor\" href=\"#3-getting-started\" aria-hidden=\"true\">#</a></h2><h3 id=\"31-signing-in\">3.1 Signing in<a class=\"anchor\" href=\"#31-signing-in\" aria-hidden=\"true\">#</a></h3><ol><li>Open the app; you'll land on the <strong>Sign in</strong> page.</li><li>Enter your <strong>Email</strong> and <strong>Password</strong>.</li><li>Click <strong>Sign in</strong>.</li></ol><p>If your credentials are wrong you'll see <strong>\"Invalid email or password.\"</strong></p><h3 id=\"32-two-factor-authentication-2fa\">3.2 Two-factor authentication (2FA)<a class=\"anchor\" href=\"#32-two-factor-authentication-2fa\" aria-hidden=\"true\">#</a></h3><p>If your account has 2FA enabled and you're on a new device, you'll be asked for a <strong>6-digit code</strong> after your password:</p><ul><li>The prompt reads <em>\"Enter the 6-digit code from your authenticator app.\"</em></li><li>Type the code from your authenticator app (Google Authenticator, Authy, 1Password, etc.). The six boxes auto-advance as you type, and the form submits automatically once all six are filled. You can also paste a full code.</li><li>A wrong code shows <strong>\"Invalid verification code\"</strong> and clears the boxes.</li><li>Check <strong>\"Remember this device for 30 days\"</strong> to skip 2FA on this device next time. (An admin can change the trusted-device duration; default is 30 days.)</li><li><strong>Back to sign in</strong> returns you to the password step.</li></ul><p>See <a href=\"#12-your-account\">Your Account</a> for how to turn 2FA on or off for yourself.</p><h3 id=\"33-account-lockout--rate-limiting\">3.3 Account lockout &amp; rate limiting<a class=\"anchor\" href=\"#33-account-lockout--rate-limiting\" aria-hidden=\"true\">#</a></h3><p>To protect against guessing:</p><ul><li><strong>5 failed attempts</strong> lock the account for <strong>15 minutes</strong>.</li><li>Repeated rapid attempts are also rate-limited per email.</li></ul><p>Both bad passwords and bad 2FA codes count toward the limit. If you're locked out, wait or ask an admin.</p><h3 id=\"34-the-navigation-bar\">3.4 The navigation bar<a class=\"anchor\" href=\"#34-the-navigation-bar\" aria-hidden=\"true\">#</a></h3><p>Across the top you'll find links to the areas you have permission to see:</p><ul><li><strong>Schedule</strong> — the grid (everyone).</li><li><strong>My Requests</strong> — submit your own requests.</li><li><strong>Requests</strong> — review everyone's requests (schedulers).</li><li><strong>Staff</strong> — the staff directory.</li><li><strong>Statistics</strong> — equity analytics.</li><li><strong>Settings</strong> — configuration (admins/schedulers).</li><li><strong>Users</strong> — login accounts (admins).</li></ul><p>On the right, your name and group badge link to your <strong>Account</strong> page, and there's a <strong>Sign out</strong> button.</p><hr><h2 id=\"4-roles--permissions\">4. Roles &amp; Permissions<a class=\"anchor\" href=\"#4-roles--permissions\" aria-hidden=\"true\">#</a></h2><p>Access is controlled by <strong>groups</strong>. Each group grants a set of fine-grained permissions. Four groups exist out of the box:</p><table><thead><tr><th>Group</th><th>Badge</th><th>What they can do</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>amber</td><td>Everything, including managing users and groups.</td></tr><tr><td><strong>Super User</strong></td><td>blue</td><td>Everything except (typically) user administration.</td></tr><tr><td><strong>Scheduler</strong></td><td>emerald</td><td>View/edit/auto-generate the schedule, view &amp; approve requests, view/edit staff, manage statistics views, edit settings.</td></tr><tr><td><strong>Staff</strong></td><td>gray</td><td>View the schedule, submit their own requests, view statistics and settings.</td></tr></tbody></table><p>Admin and Super User are <strong>system groups</strong> with a locked, full permission set. Scheduler and Staff are editable, and admins can create additional custom groups (see <a href=\"#1011-groups--permissions\">Groups &amp; Permissions</a>).</p><p>Individual permissions include things like <em>View Schedule</em>, <em>Edit Schedule</em>, <em>Auto-Scheduler</em>, <em>Submit Own Requests</em>, <em>View All Requests</em>, <em>Edit Staff</em>, <em>Manage Statistics Views</em>, <em>Edit Settings</em>, <em>Edit Auto-Generation Priority</em>, <em>Edit Users</em>, and <em>Edit Groups</em>. The full list is in <a href=\"#appendix-c--permission-reference\">Appendix C</a>.</p><blockquote><p><strong>Tip:</strong> If a nav link or button is missing for you, it's almost always a permission your group doesn't have. Ask an admin.</p></blockquote><hr><h2 id=\"5-the-schedule-grid\">5. The Schedule Grid<a class=\"anchor\" href=\"#5-the-schedule-grid\" aria-hidden=\"true\">#</a></h2><p>The grid is the heart of YoSched. It's at <strong>Schedule</strong> (the home page).</p><h3 id=\"51-layout\">5.1 Layout<a class=\"anchor\" href=\"#51-layout\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Rows are days.</strong> The view is padded out to whole pay periods, so you'll see a few dimmed days from the surrounding weeks. Each row shows the weekday and date.</li><li><strong>Columns are staff members,</strong> left to right in roster order. After the staff columns come optional <strong>dedicated columns</strong> (e.g., ICU, CARD) and <strong>count columns</strong>.</li><li>The <strong>date column</strong> on the left is sticky. Click a date to highlight (focus) the row.</li><li><strong>Staff headers</strong> show initials. Hover a header for a tooltip of that person's equity numbers (overall deviation, desirability, holiday count, and key shift counts). Manual-only staff (not auto-scheduled) show their initials in <strong>amber</strong>.</li></ul><p><strong>Visual cues on the grid:</strong></p><ul><li>Weekends have a slightly lighter row background; <strong>holidays</strong> get an amber tint (hover the date to see the holiday name).</li><li><strong>Today</strong> is ringed in light blue.</li><li>A blue top-border marks the <strong>first day of each pay period</strong>.</li><li>Each assigned cell is tinted in its shift's color, with the shift code shown.</li></ul><h3 id=\"52-selecting-and-moving-around\">5.2 Selecting and moving around<a class=\"anchor\" href=\"#52-selecting-and-moving-around\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Click</strong> a cell to make it active (blue ring). Click an already-selected cell to open the shift picker.</li><li><strong>Arrow keys</strong> move the active cell. Movement wraps between the staff columns and dedicated columns.</li><li><strong>Shift+Click</strong> selects a rectangular range from the last cell to the clicked cell.</li><li><strong>Shift+Drag</strong> selects a range by dragging.</li><li><strong>Ctrl/Cmd+Click</strong> toggles individual cells in/out of the selection (within a single staff column).</li><li>Selected cells are highlighted green; the count appears as <strong>\"N selected\"</strong> in the toolbar.</li><li><strong>Escape</strong> closes a picker or clears the selection.</li></ul><h3 id=\"53-assigning-shifts\">5.3 Assigning shifts<a class=\"anchor\" href=\"#53-assigning-shifts\" aria-hidden=\"true\">#</a></h3><p>There are four ways to assign:</p><ol><li><strong>Quick keys (fastest).</strong> Each shift type can have a single-letter hotkey (configured in Settings). Press that letter to assign the shift to the active cell or to the entire selection.</li><li><strong>The shift picker.</strong> Open it by clicking a selected cell, <strong>right-clicking</strong> a cell, or pressing <strong>Tab</strong>. The picker shows colored buttons for each shift, grouped into Work / Leave / Off. The current assignment has a white ring. A red dot on a button means a hard conflict; an amber dot means a soft warning. With a multi-cell selection, the picker shows <strong>\"Assign N cells\"</strong> and applies to all of them.</li><li><strong>Drag-to-swap.</strong> Drag a shift from one cell to another. If the target is empty the shift moves; if it's occupied the two <strong>swap</strong>.</li><li><strong>Copy/paste from Excel.</strong> Select a block, <strong>Ctrl/Cmd+C</strong> to copy, <strong>Ctrl/Cmd+V</strong> to paste a block (it fills down and right from the active cell). A summary toast reports what happened: <em>\"N set · M locked · K unknown code · X conflict · Y day-cap.\"</em></li></ol><p><strong>Clearing:</strong> Press <strong>Delete</strong> or <strong>Backspace</strong> to clear the active cell or the whole selection. The <strong>Clear</strong> button in the picker does the same. Locked cells are skipped.</p><p><strong>Per-day caps:</strong> Some shifts allow only one (or a few) per day (e.g., one <code>ORC</code>). If you try to exceed the cap, the edit snaps back with a red popover: <em>\"Only one ORC allowed per day — {date} is already full.\"</em></p><h3 id=\"54-locking-assignments\">5.4 Locking assignments<a class=\"anchor\" href=\"#54-locking-assignments\" aria-hidden=\"true\">#</a></h3><p>Locking protects an assignment. A <strong>locked</strong> cell shows a yellow ring and:</p><ul><li>Can't be dragged, dropped into, deleted, or overwritten via the picker.</li><li>Is never changed by the auto-generator.</li></ul><p>Use locks to pin hand-placed assignments you don't want the auto-generator to touch. (Manually-placed cells are also protected inside Auto-Generate even without an explicit lock — see <a href=\"#64-why-an-edit-was-rejected\">§6.4</a>.)</p><h3 id=\"55-dedicated-columns-eg-icu-card\">5.5 Dedicated columns (e.g., ICU, CARD)<a class=\"anchor\" href=\"#55-dedicated-columns-eg-icu-card\" aria-hidden=\"true\">#</a></h3><p>Shift types flagged as <strong>dedicated columns</strong> appear as their own columns on the right. Each cell lists the <strong>initials</strong> of everyone covering that shift that day.</p><ul><li>Click to select; click again (or press <strong>Enter</strong> / <strong>F2</strong>) to edit inline.</li><li>Type a comma-separated list of initials (e.g., <code>JD, AB, SM</code>). Adding initials assigns the shift; removing them clears it. Unknown initials are flagged.</li><li>Edits are <strong>all-or-nothing</strong>: if any part is blocked (a locked person, a day-cap), the whole edit is rejected.</li><li><strong>Delete/Backspace</strong> clears the whole roster for that day.</li><li>Copy/paste works column-wise too.</li></ul><h3 id=\"56-totals-counts-and-indicators\">5.6 Totals, counts, and indicators<a class=\"anchor\" href=\"#56-totals-counts-and-indicators\" aria-hidden=\"true\">#</a></h3><ul><li><strong>PP Totals</strong> button toggles a pay-period totals row at the end of each period. Each staff cell shows the <strong>+/- hours versus their target</strong>, color-coded: green = on target, red = under, amber = over, gray = no hours. Hover for the exact <em>\"hours / target (±Δ).\"</em> This preference is remembered in your browser.</li><li><strong>Count columns</strong> (right side) tally specific shift codes per day. A count turns red when that day is short of its staffing requirement.</li></ul><h3 id=\"57-alerts\">5.7 Alerts<a class=\"anchor\" href=\"#57-alerts\" aria-hidden=\"true\">#</a></h3><p>The <strong>Alerts</strong> button (with a count and color) opens a panel of issues for the current month, in three categories:</p><ol><li><strong>Pending requests</strong> — requests still awaiting a decision.</li><li><strong>Pay-period hours</strong> — staff meaningfully under or over their target (amber).</li><li><strong>Staffing coverage</strong> — a day with nobody covering a required role (red — the most serious).</li></ol><p>The button is <strong>red</strong> if there are any coverage gaps, <strong>amber</strong> for hours issues, and gray when everything is muted or clear. Each alert has a <strong>jump-to-day</strong> link (it scrolls to the day and flashes it) and a <strong>mute</strong> toggle. Muting is shared across all schedulers and persists, so muted, known issues stop nagging the whole team.</p><h3 id=\"58-navigating-months-and-pay-periods\">5.8 Navigating months and pay periods<a class=\"anchor\" href=\"#58-navigating-months-and-pay-periods\" aria-hidden=\"true\">#</a></h3><ul><li><strong>←</strong>, <strong>Today</strong>, <strong>→</strong> move between months.</li><li>Click the <strong>month/year label</strong> to open a picker: use the year arrows and the month grid to jump anywhere.</li><li>The date range shown always rounds out to whole pay periods.</li><li>For <strong>past months</strong>, a <strong>Show all staff</strong> toggle reveals people who have no assignments that month (hidden by default for a cleaner view).</li></ul><h3 id=\"59-versions-save--restore\">5.9 Versions (save &amp; restore)<a class=\"anchor\" href=\"#59-versions-save--restore\" aria-hidden=\"true\">#</a></h3><p>The <strong>Versions</strong> button (shows <code>v{N}</code>, with <code>*</code> if there are unsaved edits) opens the version history for the current month:</p><ul><li>Add an optional comment and <strong>Save version</strong> to snapshot the month.</li><li>Each version lists its number, time, and comment, with badges for <em>current</em> and <em>auto-backup</em>.</li><li><strong>Changes</strong> shows a diff against the previous version (added / removed / changed / locked, with colored before→after chips).</li><li><strong>Restore</strong> reverts the month to that version (it confirms first and auto-saves your current state before restoring).</li></ul><blockquote><p>Versions can't be saved or restored while you're in Auto-Generate (see below).</p></blockquote><h3 id=\"510-copy-undo-redo\">5.10 Copy, undo, redo<a class=\"anchor\" href=\"#510-copy-undo-redo\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Ctrl/Cmd+Z</strong> undoes; <strong>Ctrl/Cmd+Shift+Z</strong> or <strong>Ctrl+Y</strong> redoes.</li><li>The toolbar's <strong>↩ / ↪</strong> arrows do the same.</li></ul><hr><h2 id=\"6-auto-generate\">6. Auto-Generate<a class=\"anchor\" href=\"#6-auto-generate\" aria-hidden=\"true\">#</a></h2><p>Auto-Generate builds (or rebalances) the schedule for you, honoring coverage, eligibility, locks, approved requests, and hour targets — and it does so <strong>interactively</strong>, so you can nudge it and watch it adapt.</p><p>Requires the <em>Auto-Scheduler</em> and <em>View All Requests</em> permissions. Click the violet <strong>Auto-generate</strong> button to enter.</p><h3 id=\"61-how-it-works\">6.1 How it works<a class=\"anchor\" href=\"#61-how-it-works\" aria-hidden=\"true\">#</a></h3><ol><li>On entry, YoSched loads the full rule set (staff, shifts, existing assignments, requests, availability) and reproduces your current grid exactly — <strong>no changes yet</strong>.</li><li>Every edit you make — a hotkey, a picker choice, a drag, a delete — is treated as a <strong>pin</strong> (something you want kept) or a <strong>free</strong> (something you emptied).</li><li>The engine re-solves: it keeps your pins and any locked/manual cells fixed, and refills the rest to keep the schedule legal and balanced.</li><li>Cells the engine changed to compensate are ringed in <strong>amber</strong> (\"ripple\").</li></ol><p>The banner at the top shows the status (<em>\"matches the current grid (no changes yet)\"</em> or <em>\"N cell(s) changed\"</em>), any soft warnings, and rejected edits.</p><h3 id=\"62-controlling-how-far-it-ripples-scope\">6.2 Controlling how far it ripples (Scope)<a class=\"anchor\" href=\"#62-controlling-how-far-it-ripples-scope\" aria-hidden=\"true\">#</a></h3><p>Use the scope buttons in the Auto-Generate banner to control how aggressively the engine rebalances:</p><table><thead><tr><th>Scope</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Limited</strong></td><td>Smallest possible change — only what's needed to restore coverage. Least disruption. (Default; configurable in Settings.)</td></tr><tr><td><strong>Day(s)</strong></td><td>Re-solve the touched day(s) and rebalance their hours.</td></tr><tr><td><strong>Pay period</strong></td><td>Rebalance the whole affected pay period(s).</td></tr><tr><td><strong>Whole range</strong></td><td>Re-solve the entire visible month. Maximum rebalance.</td></tr></tbody></table><h3 id=\"63-sandbox-undoredo\">6.3 Sandbox undo/redo<a class=\"anchor\" href=\"#63-sandbox-undoredo\" aria-hidden=\"true\">#</a></h3><p>While in Auto-Generate, <strong>↩ / ↪</strong> (and Ctrl+Z / Ctrl+Y) undo and redo within the sandbox only — they don't touch your saved schedule until you Accept.</p><h3 id=\"64-why-an-edit-was-rejected\">6.4 Why an edit was rejected<a class=\"anchor\" href=\"#64-why-an-edit-was-rejected\" aria-hidden=\"true\">#</a></h3><p>If an edit isn't allowed, the whole edit snaps back and a red popover explains why:</p><ul><li><strong>Ineligible</strong> — the person isn't qualified for that shift.</li><li><strong>Unavailable</strong> — their availability rules forbid it.</li><li><strong>Request-blocked</strong> — an approved hard time-off/leave request forbids work, or an approved request forbids that specific shift.</li><li><strong>Manual-locked</strong> — a cell you placed by hand before entering can't be changed by the engine.</li><li><strong>Day-full</strong> — the shift's per-day cap is already reached.</li></ul><p><strong>Soft warnings</strong> (amber, in the banner) flag things that are allowed but not ideal (e.g., coverage slightly below the floor, hours drifting). You can accept them.</p><h3 id=\"65-accept-or-cancel\">6.5 Accept or Cancel<a class=\"anchor\" href=\"#65-accept-or-cancel\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Accept</strong> commits the result. What you see is what you save (WYSIWYG): every cell that differs from the saved schedule — your edits <em>and</em> the engine's fills — is written, tagged with source <strong>Auto</strong> for the run's month.</li><li><strong>Cancel</strong> discards everything and restores the saved grid.</li></ul><h3 id=\"66-clear-auto\">6.6 Clear Auto<a class=\"anchor\" href=\"#66-clear-auto\" aria-hidden=\"true\">#</a></h3><p>The red <strong>Clear Auto</strong> button removes all auto-generated cells for the current month (including any that spilled into adjacent months from the same run). Hand-placed and locked cells are left alone.</p><hr><h2 id=\"7-requests\">7. Requests<a class=\"anchor\" href=\"#7-requests\" aria-hidden=\"true\">#</a></h2><p>Requests let staff ask to work — or avoid — shifts, and let schedulers decide.</p><h3 id=\"71-for-staff-the-my-requests-page\">7.1 For staff: the <em>My Requests</em> page<a class=\"anchor\" href=\"#71-for-staff-the-my-requests-page\" aria-hidden=\"true\">#</a></h3><p>Open <strong>My Requests</strong> (requires the <em>Submit Own Requests</em> permission and a login that's linked to your staff record). If your login isn't linked yet, you'll see a note asking you to contact an administrator.</p><p><strong>To submit a request:</strong></p><ol><li>Choose a category:<ul><li><strong>Request a shift</strong> — \"Shift(s) I'd like — work, a leave type, or the day off. Scheduling any one of them satisfies the request.\" (Selecting several is an <strong>OR</strong> — any one fulfills it.)</li><li><strong>Avoid a shift</strong> — \"Please don't assign me these shift(s).\" (An <strong>AND</strong> — none should be assigned.)</li></ul></li><li>Pick a <strong>Start date</strong> and, optionally, an <strong>End date</strong> (same day if blank).</li><li>Select one or more <strong>shifts</strong> (work shifts and/or leave types, including the day-off shift). Selected chips are highlighted.</li><li><em>(For time-off requests)</em> a <strong>leave-queue</strong> note tells you how many people already requested leave on the busiest day in your range and where you'd sit in the queue. If you're over the department's suggested limit, you can still submit — <em>\"the scheduler will decide.\"</em></li><li><em>(For a pure day-off request)</em> set <strong>\"How should we give you this day off?\"</strong> — drag the strategies into your preferred order (e.g., place an <code>ORC</code> the day before, pair two <code>ORL</code>s, or use a specific leave type). It's a best-effort preference, not a guarantee.</li><li>Toggle <strong>\"I'm flexible — treat this as a preference, not a firm request\"</strong> to make it a soft request rather than a firm (hard) one.</li><li>Add an optional <strong>note</strong>.</li><li>Click <strong>Submit request</strong>.</li></ol><p><strong>After submitting,</strong> a printable <strong>confirmation receipt</strong> appears (with your name, the request, dates, status, timestamp, and a reference ID) — you can <strong>Print</strong> or <strong>Close</strong> it.</p><p><strong>Your requests</strong> are listed below the form, newest first, each with its status badge (pending / approved / declined / withdrawn / fulfilled), a <strong>Receipt</strong> link, and — for pending ones — a <strong>Withdraw</strong> button.</p><h3 id=\"72-entering-requests-on-the-grid-request-mode\">7.2 Entering requests on the grid (Request Mode)<a class=\"anchor\" href=\"#72-entering-requests-on-the-grid-request-mode\" aria-hidden=\"true\">#</a></h3><p>Schedulers can enter requests directly on the grid. Press <strong><code>/</code></strong> to toggle <strong>Request Mode</strong> (a violet banner appears). Now keyboard letters create <em>requests</em> instead of assignments:</p><table><thead><tr><th>Keys</th><th>Meaning</th></tr></thead><tbody><tr><td><em>letter</em></td><td>Want this shift (hard)</td></tr><tr><td><strong>Shift</strong> + <em>letter</em></td><td>Avoid this shift (hard)</td></tr><tr><td><strong>Alt</strong> + <em>letter</em></td><td>Want this shift (soft preference)</td></tr><tr><td><strong>Shift+Alt</strong> + <em>letter</em></td><td>Avoid this shift (soft)</td></tr><tr><td><strong>+</strong></td><td>Approve every pending request on the cell/selection</td></tr><tr><td><strong>!</strong></td><td>Deny every pending request on the cell/selection</td></tr><tr><td><strong>^</strong></td><td>Reset approved/denied requests back to pending</td></tr><tr><td><strong>Delete/Backspace</strong></td><td>Remove the request(s) — the shift on the schedule stays</td></tr></tbody></table><p>Press <strong><code>/</code></strong> again to leave Request Mode. The <strong>RQ</strong> toolbar button (with its filter menu: All / Approved only / Pending only / Denied only) controls the request overlay on the grid. In the overlay, a solid ring is an approved request, a faint ring is pending, and struck-through rose text is denied; colors indicate want (green), avoid (rose), leave (amber), off (sky), or mixed (violet).</p><h3 id=\"73-for-schedulers-the-requests-page\">7.3 For schedulers: the <em>Requests</em> page<a class=\"anchor\" href=\"#73-for-schedulers-the-requests-page\" aria-hidden=\"true\">#</a></h3><p>Open <strong>Requests</strong> (requires <em>View All Requests</em>). The page lists every request with:</p><ul><li><strong>Status tabs</strong> across the top (all / pending / approved / declined / withdrawn / fulfilled) with live counts.</li><li>A <strong>search box</strong> (\"Search requests…\") that matches across staff, dates, shift codes, status, notes, approver, and more.</li><li>A sortable table: <strong>Staff, Dates, Request, Status, Source, Received, Approved</strong>.</li></ul><p><strong>Acting on requests</strong> (requires <em>Edit Schedule</em>):</p><ul><li>Pending → <strong>Approve</strong> (places the shift if it can) or <strong>Decline</strong> or <strong>Delete</strong>.</li><li>Approved → <strong>Unapprove</strong> (back to pending) or <strong>Delete</strong>.</li><li>Declined/Withdrawn → <strong>Reopen</strong> or <strong>Delete</strong>.</li></ul><p>When you <strong>Approve</strong> a single-shift request, the shift is placed on the schedule immediately (if no locked day blocks it). Approving also <strong>reconciles</strong>: if the placed shift now satisfies another pending request, that one auto-approves too. If you unapprove something whose shift is still on the grid, an amber prompt warns you and offers <strong>Clear shift(s)</strong> or <strong>Keep</strong>.</p><blockquote><p><strong>Viewers</strong> (those with <em>View All Requests</em> but not <em>Edit Schedule</em>) see all requests and statuses but no action buttons, and the approver's name stays hidden.</p></blockquote><h3 id=\"74-how-pending-vs-approved-requests-affect-auto-generation\">7.4 How pending vs. approved requests affect auto-generation<a class=\"anchor\" href=\"#74-how-pending-vs-approved-requests-affect-auto-generation\" aria-hidden=\"true\">#</a></h3><p>Admins set two policies in <strong>Settings → Scheduling Preferences</strong>:</p><ul><li><strong>Pending requests in the auto-schedule:</strong> <em>Only approved</em> (ignore pending) / <em>As preferences</em> (pending count as soft nudges) / <em>Full strength</em> (pending honored like approved). <strong>Approved</strong> requests always apply at their stated strength.</li><li><strong>Conflicting shift requests:</strong> <em>Reconcile (first-come)</em> — place tentatively, keep only if conflict-free, earliest request wins a contested slot — or <em>Honor always</em> — force every requested shift and keep it. Human-approved placements are never revoked either way.</li></ul><hr><h2 id=\"8-staff-management\">8. Staff Management<a class=\"anchor\" href=\"#8-staff-management\" aria-hidden=\"true\">#</a></h2><p>Open <strong>Staff</strong> (requires <em>View Staff</em>; editing requires <em>Edit Staff</em>).</p><h3 id=\"81-the-directory\">8.1 The directory<a class=\"anchor\" href=\"#81-the-directory\" aria-hidden=\"true\">#</a></h3><p>A sortable table of staff, with columns: <strong>ID</strong> (initials), <strong>Name</strong>, <strong>Type</strong> (employment type), <strong>FTE</strong>, <strong>Availability</strong> (a mini Sun–Sat grid; an amber dot means advanced rules also apply that day), <strong>Auto</strong> (✓ if auto-scheduled), and <strong>Login</strong> (account status with a <em>manage →</em> link).</p><p>The top shows counts (\"N auto-scheduled, M manual\", plus inactive). Use <strong>Show/Hide inactive</strong> to toggle archived staff and <strong>+ Add Staff</strong> to create someone. After a save or delete, an 8-second <strong>Undo</strong> toast lets you reverse it.</p><h3 id=\"82-creating-and-editing-a-staff-member\">8.2 Creating and editing a staff member<a class=\"anchor\" href=\"#82-creating-and-editing-a-staff-member\" aria-hidden=\"true\">#</a></h3><p><strong>+ Add Staff</strong> creates a record (defaults: name \"New Staff\", initials \"NEW\", the first employment type) and opens the editor. Click any row to edit. The editor has four sections.</p><p><strong>Identity:</strong></p><ul><li><strong>Initials</strong> — the 2–4 character grid code.</li><li><strong>Full name.</strong></li><li><strong>Employment type</strong> — choosing a type applies <em>that type's defaults</em> (auto-schedule, FTE, eligible shifts, availability), replacing existing custom values.</li><li><strong>FTE</strong> — for FTE types, a value like 0.75 or 1.0 (up to three decimals). Drives hour targets and statistics normalization.</li><li><strong>Active</strong> — uncheck to archive (hidden from the schedule, excluded from auto-scheduling).</li><li><strong>Auto-schedule</strong> — uncheck to make this person manual-only.</li></ul><p><strong>Scheduling — Auto-schedule these shifts:</strong> Toggle which shifts this person is eligible for (grouped Work / Leave). Each eligible shift can expand to configure:</p><ul><li><strong>Eligibility rules</strong> — add rules making the person <em>eligible</em> or <em>ineligible</em> on certain dates, as a <strong>Hard</strong> rule (must obey) or <strong>Prefer</strong> (try to). Each rule uses the <a href=\"#84-the-recurrence-picker\">recurrence picker</a>.</li><li><strong>Count target</strong> — how often they should work the shift: a mode (<em>at least / at most / exactly / between</em>), a count, and a window (<em>week / pay period / month / rolling N days</em>). Example: \"at least 2 CALL per pay period.\"</li></ul><p><strong>Scheduling — Override shift hours:</strong> Turn on to set custom weekday/weekend/holiday hours for specific shifts for this person (blank means \"use the shift's default\"). A <strong>reset</strong> link clears a shift's overrides.</p><p><strong>Scheduling — Availability:</strong></p><ul><li><strong>Working days</strong> — seven quick toggle buttons (Sun–Sat) for simple \"every week\" availability. An amber dot marks days also governed by an advanced rule.</li><li><strong>Rules</strong> — richer patterns. Each rule sets <em>Available</em> or <em>Not available</em>, a recurrence pattern, an enforcement level (<em>Hard</em> / <em>Soft preference</em>), and an optional <strong>condition</strong> (\"only when {another staffer} is working / is not working\"). A plain-English summary appears under each rule.</li></ul><p><strong>Scheduling — Standing commitments:</strong> Recurring shifts the auto-generator pre-assigns before anything else (e.g., a weekly leadership shift). Each commitment picks a shift, a recurrence (including an <strong>Any day</strong> option), and optional notes.</p><h3 id=\"83-removing-a-staff-member\">8.3 Removing a staff member<a class=\"anchor\" href=\"#83-removing-a-staff-member\" aria-hidden=\"true\">#</a></h3><p>In the editor, <strong>Delete</strong> asks to confirm. If the person has <strong>no assignments</strong> they're permanently deleted; if they <strong>have assignments</strong> they're <strong>deactivated</strong> instead (reversible by editing them and re-checking <em>Active</em>). An undo toast appears either way.</p><h3 id=\"84-the-recurrence-picker\">8.4 The recurrence picker<a class=\"anchor\" href=\"#84-the-recurrence-picker\" aria-hidden=\"true\">#</a></h3><p>Used by eligibility rules, availability rules, and standing commitments to say <em>which occurrences</em> a rule covers:</p><ol><li><strong>Pick weekday(s)</strong> — one or more of Sun–Sat (standing commitments also offer <strong>Any day</strong>).</li><li><strong>Pick an occurrence pattern:</strong><ul><li><strong>Every week</strong> — every occurrence of those weekdays.</li><li><strong>Pay-period week 1 / week 2</strong> — only the first or second week of the pay period.</li><li><strong>Specific weeks of the month</strong> — 1st / 2nd / 3rd / 4th / 5th / Last (multi-select).</li><li><strong>Specific weeks of the pay period</strong> — the same ordinals within the pay period.</li><li><strong>Every N weeks</strong> — a cycle length and slot (e.g., \"every other Monday\").</li><li><strong>Every N pay periods</strong> — the same, indexed by pay periods.</li></ul></li></ol><p>A live plain-English sentence (e.g., <em>\"1st and 3rd Fridays of the month\"</em>) confirms what you've built.</p><hr><h2 id=\"9-statistics--equity\">9. Statistics &amp; Equity<a class=\"anchor\" href=\"#9-statistics--equity\" aria-hidden=\"true\">#</a></h2><p>Open <strong>Statistics</strong> (requires <em>View Statistics</em>). This page shows per-staff workload and fairness metrics with interactive charts.</p><h3 id=\"91-filters-and-controls\">9.1 Filters and controls<a class=\"anchor\" href=\"#91-filters-and-controls\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Date range</strong> — <em>All dates</em>, specific <strong>Pay periods</strong>, <strong>Years</strong>, or a <strong>Custom</strong> from/to range. Everything recomputes over the chosen range.</li><li><strong>Staff picker</strong> — filter by <strong>employment type</strong>, a <strong>minimum FTE</strong>, and/or specific people <strong>by name</strong> (chips). Filters combine.</li><li><strong>Metric</strong> — what to chart/measure: <em>All shifts</em>, a specific shift code, <em>Holiday</em>, or <em>Desirability</em>. Only equity factors your admin has enabled appear.</li><li><strong>Chart type</strong> — <em>Bar</em>, <em>Pie</em> (donut), or <em>Heatmap</em>. Incompatible metric/chart combinations are disabled and fall back to Bar.</li><li><strong>Hide/Show Charts</strong> and <strong>Hide/Show Tallies</strong> declutter the view; tallies add raw count columns for every shift code.</li></ul><h3 id=\"92-the-table\">9.2 The table<a class=\"anchor\" href=\"#92-the-table\" aria-hidden=\"true\">#</a></h3><p>Each row is a staff member. Columns depend on the enabled equity factors and the tallies toggle, and may include:</p><ul><li><strong>Desirability</strong> — an FTE-normalized z-score of undesirable-shift burden. Green (&gt; +0.3) means <em>less</em> burden than average; red (&lt; −0.3) means <em>more</em>; gray is near average. (Positive = treated favorably; negative = overburdened.)</li><li><strong>Opp. Adj.</strong> — opportunity-adjusted desirability, which accounts for people having different eligible shifts so they aren't unfairly flagged.</li><li><strong>Holidays</strong> — holidays worked.</li><li><strong>Shift-code columns</strong> — counts per tracked shift.</li><li><strong>Hours</strong> — FTE-counted hours.</li><li><strong>Work Days / Leave Days.</strong></li></ul><p>Click any header to sort. Click a row to open the <strong>detail panel</strong>.</p><h3 id=\"93-the-staff-detail-panel-radar\">9.3 The staff detail panel (radar)<a class=\"anchor\" href=\"#93-the-staff-detail-panel-radar\" aria-hidden=\"true\">#</a></h3><p>Clicking a row opens a side panel with a <strong>radar chart</strong> comparing that person (solid blue) to the <strong>department average</strong> (dashed gray, the 0σ ring). Axes are the enabled factors (Undesirable, Holidays, each shift code). Outward = more burden than average; inward = less. Hover an axis for the exact z-score and a description.</p><h3 id=\"94-the-charts\">9.4 The charts<a class=\"anchor\" href=\"#94-the-charts\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Bar — Shift Distribution:</strong> stacked bars per staff by shift code (and Holidays). Toggle codes on/off via the legend chips. Can be shown per 1.0 FTE.</li><li><strong>Pie — Department Share:</strong> a donut of each person's share of the chosen metric.</li><li><strong>Heatmap — Equity Grid:</strong> staff (columns) × shift codes (rows); each cell shows the raw count colored by z-score (yellow = below average, red = well above).</li></ul><p>Summary cards above the charts show department averages per 1.0 FTE.</p><h3 id=\"95-saved-views--export\">9.5 Saved views &amp; export<a class=\"anchor\" href=\"#95-saved-views--export\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Saved views</strong> (requires <em>Manage Statistics Views</em>) store a full filter/metric/chart configuration. <strong>Save as…</strong> creates one (optionally <strong>Shared</strong> with everyone, or private). You can <strong>Save</strong> (overwrite), <strong>Rename</strong>, toggle <strong>Share/Make private</strong>, or <strong>Delete</strong>. <strong>↺ Reset</strong> returns all controls to defaults.</li><li><strong>Export CSV</strong> downloads the current table (filters and visible columns applied).</li><li><strong>Export PNG</strong> downloads the current chart as a high-resolution image.</li></ul><h3 id=\"96-reading-the-numbers\">9.6 Reading the numbers<a class=\"anchor\" href=\"#96-reading-the-numbers\" aria-hidden=\"true\">#</a></h3><ul><li>A <strong>negative, red</strong> desirability score means that person is carrying <em>more</em> undesirable work than peers — a fairness flag worth acting on.</li><li>Deviations beyond <strong>±0.3</strong> are highlighted; beyond <strong>±2σ</strong> on the radar is a statistical outlier worth investigating.</li><li>Use <strong>Opportunity-Adjusted</strong> when people have very different eligible-shift sets.</li></ul><hr><h2 id=\"10-settings\">10. Settings<a class=\"anchor\" href=\"#10-settings\" aria-hidden=\"true\">#</a></h2><p>Open <strong>Settings</strong> (requires <em>View Settings</em>; most changes need <em>Edit Settings</em>). Without edit permission you'll see a <strong>\"View-only\"</strong> banner and disabled controls. Sections are collapsible (state remembered in your browser); use <strong>Reveal all</strong> / <strong>Collapse all</strong> at the top. Each section shows a <em>Saving… / Saved / Error</em> status, and many actions offer an <strong>Undo</strong> toast.</p><h3 id=\"101-shift-types\">10.1 Shift Types<a class=\"anchor\" href=\"#101-shift-types\" aria-hidden=\"true\">#</a></h3><p><em>Configure shift codes, durations, and rules.</em> The core building block. For each shift:</p><ul><li><strong>Code</strong>, <strong>Name</strong>, <strong>Color</strong>, <strong>Category</strong> (Work / Leave / Other).</li><li><strong>Hours per shift</strong> for <strong>weekdays</strong>, <strong>weekends</strong>, and <strong>holidays</strong> (holiday overrides weekend; set 0 where a shift doesn't accrue).</li><li><strong>Quick key</strong> — the single letter that assigns it on the grid.</li><li>Flags: <strong>This is a leave type</strong>, <strong>Counts toward FTE hours</strong>, <strong>Counts as holiday work</strong>.</li><li>Auto-scheduling: <strong>Auto-schedulable</strong>, <strong>Scheduling order</strong> (lower = placed first), <strong>Pair Saturday and Sunday</strong>, <strong>Pair with leading/following holiday</strong>, <strong>Can be assigned on days off</strong>, <strong>Default shift for filling hours</strong>, <strong>Represents a day off</strong>, <strong>Dedicated column</strong>, <strong>Maximum per day</strong>.</li><li><strong>Shift follow rules</strong> (per shift) — restrict what may be scheduled the <em>next</em> day, in <strong>Allow</strong> or <strong>Block</strong> mode, with an <em>any off-shift</em> toggle and per-shift checkboxes (e.g., after <code>CALL</code>, only <code>ADM</code> is allowed).</li><li><strong>Required follower</strong> — automatically place another shift after this one (e.g., <code>ADM</code> after <code>CALL</code>, or a day off after <code>ORC</code>), either <em>after each day</em> or <em>after a run</em>, and optionally counting toward staffing/targets.</li><li>Printing options: <strong>Print background</strong> color and <strong>Bold on schedule</strong>.</li></ul><p>Drag rows to reorder; <strong>Add Shift Type</strong> / <strong>Delete Shift Type</strong> (delete is disabled while a shift is in use).</p><h3 id=\"102-employment-types\">10.2 Employment Types<a class=\"anchor\" href=\"#102-employment-types\" aria-hidden=\"true\">#</a></h3><p><em>Define employment categories and their default scheduling values.</em> Each type sets the defaults applied to new staff of that type: <strong>auto-schedule</strong> on/off, <strong>FTE percentage</strong>, <strong>default eligible shifts</strong>, and <strong>default availability</strong> (quick working days plus advanced rules). Delete is allowed only when no staff use the type.</p><h3 id=\"103-staffing-rules\">10.3 Staffing Rules<a class=\"anchor\" href=\"#103-staffing-rules\" aria-hidden=\"true\">#</a></h3><p><em>Minimum staff per shift type per day of the week.</em> A grid of days (Mon–Sun plus a <strong>Holiday</strong> row) × shift codes; each cell is the minimum required count. The auto-generator always satisfies these first. Add/replace/remove columns via the header menu; <strong>Save Staffing Rules</strong> to apply.</p><h3 id=\"104-scheduling-preferences\">10.4 Scheduling Preferences<a class=\"anchor\" href=\"#104-scheduling-preferences\" aria-hidden=\"true\">#</a></h3><p><em>Controls how the auto-scheduler places days off — staffing is always respected first.</em></p><ul><li><strong>Prefer 3-day weekends</strong>, <strong>Prefer 4-day weekends</strong>, <strong>Prefer sequential days off</strong> (all on by default).</li><li><strong>Soft leave limit per day</strong> — warn (don't block) when this many people already have leave on a date (0 = no limit).</li><li><strong>Default scope of Live changes</strong> — Limited / Day / Pay Period / Range (the default ripple scope for <a href=\"#62-controlling-how-far-it-ripples-scope\">Auto-Generate</a>).</li><li><strong>Pending requests in the auto-schedule</strong> — Only approved / As preferences / Full strength.</li><li><strong>Conflicting shift requests</strong> — Reconcile (first-come) / Honor always.</li><li><strong>Default day-off fulfillment order</strong> — a reorderable list of strategies (e.g., ORC adjacent, ORL pair, then specific leave types) the engine tries in order.</li></ul><h3 id=\"105-pay-period-preferences\">10.5 Pay-period Preferences<a class=\"anchor\" href=\"#105-pay-period-preferences\" aria-hidden=\"true\">#</a></h3><p><em>Department-wide shift targets, expressed per 1.0 FTE.</em> One target per auto-schedulable work shift (a frequency such as \"2–4 CALL per pay period\"), with a <strong>Soft</strong> or <strong>Hard</strong> strength. The engine scales each target to a person's FTE; per-staff targets override these.</p><h3 id=\"106-shift-desirability\">10.6 Shift Desirability<a class=\"anchor\" href=\"#106-shift-desirability\" aria-hidden=\"true\">#</a></h3><p><em>Rate how desirable each shift is per day of week.</em> A grid (work shifts × Sun–Sat) of weights from <strong>−5 (terrible)</strong> to <strong>+5 (great)</strong>, color-coded red→green. The equity engine and auto-generator use these to bias placement and measure fairness.</p><h3 id=\"107-equity-factors\">10.7 Equity Factors<a class=\"anchor\" href=\"#107-equity-factors\" aria-hidden=\"true\">#</a></h3><p><em>Which metrics factor into the equity score, and their weights.</em> Enable/disable factors (built-in <strong>Desirability</strong> and <strong>Holiday Work</strong>, plus per-shift <strong>counts</strong>), set each factor's weight (auto-normalized to a percentage), and reorder them. All values are FTE-normalized.</p><h3 id=\"108-auto-generation-priority\">10.8 Auto-Generation Priority<a class=\"anchor\" href=\"#108-auto-generation-priority\" aria-hidden=\"true\">#</a></h3><p><em>How auto-generation decides what to schedule when goals compete.</em> Requires the <em>Edit Auto-Generation Priority</em> permission (admin-only; others see a lock).</p><p>Some constraints are <strong>always enforced</strong> and shown pinned/read-only: one shift per person per day, eligibility, locked &amp; manual cells, approved hard requests, and per-day caps.</p><p>Below those, a <strong>drag-to-rank</strong> list orders the competing goals (e.g., hard per-staff limits, coverage, over-hours, under-hours, requests, fairness). Higher items win — a factor is never traded away to improve one ranked below it. Dragging updates a <strong>local draft</strong>; <strong>Save</strong> to apply or <strong>Cancel</strong> to revert. You can also store named <strong>profiles</strong> (snapshotted with who saved them and when) and <strong>Apply</strong> them later.</p><h3 id=\"109-printed-schedule-columns\">10.9 Printed-schedule columns<a class=\"anchor\" href=\"#109-printed-schedule-columns\" aria-hidden=\"true\">#</a></h3><p>Three sections shape the <strong>printed</strong> schedule only (the on-screen grid always shows all staff):</p><ul><li><strong>Staff Columns on Printed Schedule</strong> — include/exclude rules deciding who gets their own column (by employment type, FTE bounds, and shift conditions).</li><li><strong>Additional Columns on Printed Schedule</strong> — extra aggregate columns listing the initials of matching staff per day, with a <strong>Catch-all</strong> option and a <strong>Suppress members</strong> option.</li><li><strong>Count Columns</strong> — columns that count specific shifts per day (these also appear on the on-screen grid).</li></ul><h3 id=\"1010-calendar-pay-periods--holidays\">10.10 Calendar: Pay Periods &amp; Holidays<a class=\"anchor\" href=\"#1010-calendar-pay-periods--holidays\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Pay Periods</strong> — set <strong>Hours per Pay Period (1.0 FTE)</strong> (e.g., 80), then batch-create periods from a <strong>First Period Start</strong> date and a <strong>Number of Periods</strong>. <strong>Regenerate</strong> replaces all periods (it confirms first). A preview table lists them.</li><li><strong>Holidays</strong> — <strong>Auto-populate federal holidays</strong> for the configured years (with observed-date handling), or add custom holidays by date and name. Remove any from the list.</li></ul><h3 id=\"1011-general--system\">10.11 General &amp; System<a class=\"anchor\" href=\"#1011-general--system\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Date Format</strong> — choose one of nine formats (default <em>MMMM D, YYYY</em>); it applies everywhere dates appear.</li><li><strong>Email (SMTP)</strong> — configure outbound mail for request confirmations: enable, host, port, implicit-TLS toggle, username, password, and from-address. <strong>Send test email</strong> verifies it. Nothing sends until this is filled in and enabled.</li><li><strong>Groups &amp; Permissions</strong> — manage the groups described in <a href=\"#4-roles--permissions\">§4</a>. View each group's permission count and member count; create custom groups with a permission grid; edit non-system groups. System groups (Admin, Super User, Scheduler, Staff) have locked names; system groups can't be deleted, and a group with members can't be deleted.</li></ul><hr><h2 id=\"11-user-management\">11. User Management<a class=\"anchor\" href=\"#11-user-management\" aria-hidden=\"true\">#</a></h2><p>Open <strong>Users</strong> (requires <em>View Users</em>; editing requires <em>Edit Users</em>). This manages <strong>login accounts</strong>, which are distinct from staff records (a login can be <em>linked</em> to a staff member).</p><h3 id=\"111-the-users-table\">11.1 The users table<a class=\"anchor\" href=\"#111-the-users-table\" aria-hidden=\"true\">#</a></h3><p>Sortable columns: <strong>Name, Email, Group, Staff</strong> (linked staff member), <strong>Status</strong> (<em>Active</em> / <em>Disabled</em> / <em>Needs setup</em>), <strong>2FA</strong> (On/Off), and <strong>Actions</strong>. Your sort choice is saved to your profile.</p><p>At the top, admins with <em>Edit Settings</em> can set how long <strong>2FA trusted devices</strong> are remembered (1–365 days; default 30).</p><h3 id=\"112-creating-and-editing-users\">11.2 Creating and editing users<a class=\"anchor\" href=\"#112-creating-and-editing-users\" aria-hidden=\"true\">#</a></h3><p><strong>Add User</strong> opens a form: <strong>Name</strong>, <strong>Email</strong>, <strong>Password</strong>, <strong>Confirm password</strong>, and <strong>Group</strong>. Passwords must be at least 8 characters with upper- and lower-case and a number. <strong>Edit User</strong> pre-fills the fields; leave the password blank to keep the current one.</p><h3 id=\"113-activating-resetting-and-deleting\">11.3 Activating, resetting, and deleting<a class=\"anchor\" href=\"#113-activating-resetting-and-deleting\" aria-hidden=\"true\">#</a></h3><ul><li><strong>Status</strong> toggles Active/Disabled. A login <strong>can't be activated</strong> until it has both an email and a password (<em>\"Set an email and password (Edit) before this login can be activated.\"</em>).</li><li><strong>Reset 2FA</strong> clears the user's 2FA so they can set it up again.</li><li>For <strong>staff-linked</strong> logins, <strong>Reset</strong> disables the login and clears its email/password while keeping the staff member. For <strong>standalone</strong> logins, <strong>Delete</strong> removes the account.</li><li><strong>Safety guard:</strong> any change that would leave <strong>no active administrator</strong> is blocked.</li></ul><h3 id=\"114-linking-staff-to-logins\">11.4 Linking staff to logins<a class=\"anchor\" href=\"#114-linking-staff-to-logins\" aria-hidden=\"true\">#</a></h3><p>When a staff member is created, a disabled \"Staff\" login shell is provisioned automatically. An admin completes it (adds email + password) and activates it from this page; the <strong>Staff</strong> column then shows the linked person.</p><h3 id=\"115-login-activity-log\">11.5 Login activity log<a class=\"anchor\" href=\"#115-login-activity-log\" aria-hidden=\"true\">#</a></h3><p>The collapsible <strong>Login Activity</strong> section lists recent attempts: <strong>Time, Email, Result</strong> (Success/Failed), <strong>Detail</strong> (e.g., bad password, bad TOTP, unknown email, rate limited, locked, disabled, trusted device, TOTP verified), <strong>IP</strong>, and <strong>Browser</strong>, newest first.</p><hr><h2 id=\"12-your-account\">12. Your Account<a class=\"anchor\" href=\"#12-your-account\" aria-hidden=\"true\">#</a></h2><p>Open <strong>Account</strong> (your name in the top-right). You'll see your <strong>Profile</strong> (name, email, group) and two actions:</p><ul><li><strong>Change Password</strong> — enter your current password, then a new one (min 8 chars, upper, lower, and a number) twice. <strong>Update password</strong> confirms with <em>\"Password updated.\"</em></li><li><strong>Two-Factor Authentication</strong> — if disabled, <strong>Set up 2FA</strong> shows a <strong>QR code</strong> to scan with your authenticator app (or a manual key under <em>\"Can't scan?\"</em>); after <strong>I've scanned it</strong>, enter a 6-digit code to confirm. If enabled, <strong>Disable 2FA</strong> turns it off after a confirmation.</li></ul><hr><h2 id=\"13-printing\">13. Printing<a class=\"anchor\" href=\"#13-printing\" aria-hidden=\"true\">#</a></h2><p>Click <strong>Print</strong> on the grid (or Ctrl/Cmd+P). The printout hides all chrome (toolbar, banners, pickers, tooltips) and adds a centered <strong>YoSched</strong> title with the month. What appears is shaped by the <strong>printed-schedule</strong> settings in <a href=\"#109-printed-schedule-columns\">§10.9</a>: staff-column include/exclude rules, aggregate columns (with optional member suppression), count columns, and per-shift print background colors and bold codes. Confirmation receipts on the <strong>My Requests</strong> page print the same way.</p><hr><h2 id=\"appendix-a--keyboard-shortcuts\">Appendix A — Keyboard Shortcuts<a class=\"anchor\" href=\"#appendix-a--keyboard-shortcuts\" aria-hidden=\"true\">#</a></h2><p><strong>Navigation &amp; selection</strong></p><table><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td>Arrow keys</td><td>Move the active cell</td></tr><tr><td>Click</td><td>Make a cell active</td></tr><tr><td>Click a selected cell</td><td>Open the shift picker</td></tr><tr><td>Shift + Click</td><td>Select a rectangular range</td></tr><tr><td>Shift + Drag</td><td>Select a range by dragging</td></tr><tr><td>Ctrl/Cmd + Click</td><td>Add/remove a cell from the selection</td></tr><tr><td>Right-click / Tab</td><td>Open the shift picker</td></tr><tr><td>Escape</td><td>Close the picker or clear the selection</td></tr></tbody></table><p><strong>Assigning</strong></p><table><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><em>letter</em></td><td>Assign the shift mapped to that quick key</td></tr><tr><td>Drag a shift</td><td>Move it (swap if the target is occupied)</td></tr><tr><td>Delete / Backspace</td><td>Clear the cell(s)</td></tr><tr><td>Enter / F2 (dedicated column)</td><td>Edit the day's roster inline</td></tr><tr><td>Ctrl/Cmd + C / V</td><td>Copy / paste a block (Excel-compatible)</td></tr><tr><td>Ctrl/Cmd + Z</td><td>Undo</td></tr><tr><td>Ctrl/Cmd + Shift + Z, or Ctrl + Y</td><td>Redo</td></tr></tbody></table><p><strong>Request Mode</strong> (toggle with <code>/</code>)</p><table><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td>/</td><td>Toggle Request Mode</td></tr><tr><td><em>letter</em></td><td>Want this shift (hard)</td></tr><tr><td>Shift + <em>letter</em></td><td>Avoid this shift (hard)</td></tr><tr><td>Alt + <em>letter</em></td><td>Want (soft)</td></tr><tr><td>Shift + Alt + <em>letter</em></td><td>Avoid (soft)</td></tr><tr><td>+</td><td>Approve pending request(s) on the cell/selection</td></tr><tr><td>!</td><td>Deny pending request(s)</td></tr><tr><td>^</td><td>Reset request(s) to pending</td></tr><tr><td>Delete / Backspace</td><td>Remove the request(s) (shift stays)</td></tr></tbody></table><hr><h2 id=\"appendix-b--glossary\">Appendix B — Glossary<a class=\"anchor\" href=\"#appendix-b--glossary\" aria-hidden=\"true\">#</a></h2><ul><li><strong>Assignment</strong> — one staff member, one shift, one day (a grid cell).</li><li><strong>Auto / Manual / Imported / Request-placed</strong> — the <em>source</em> of an assignment.</li><li><strong>Coverage / staffing requirement</strong> — the minimum staff a shift needs on a day.</li><li><strong>Dedicated column</strong> — a shift shown as its own column listing its roster's initials.</li><li><strong>Desirability</strong> — a −5…+5 rating of how pleasant a shift is on a given weekday.</li><li><strong>Equity / z-score</strong> — an FTE-normalized fairness measure vs. the department average.</li><li><strong>FTE</strong> — Full-Time Equivalent; scales hour targets and normalizes statistics.</li><li><strong>Follow rule</strong> — a restriction on what shift may come the day after another.</li><li><strong>Hard vs. soft</strong> — a hard rule/request must be honored; a soft one is a preference.</li><li><strong>Lock</strong> — protects a cell from auto-generation and accidental edits.</li><li><strong>Pay period</strong> — a 14-day window for hour targets and totals.</li><li><strong>Required follower</strong> — a shift automatically placed after another (e.g., <code>ADM</code> after <code>CALL</code>).</li><li><strong>Ripple</strong> — cells the auto-generator changed (amber) to keep the schedule legal after your edit.</li><li><strong>Standing commitment</strong> — a recurring shift pre-assigned before other scheduling.</li></ul><hr><h2 id=\"appendix-c--permission-reference\">Appendix C — Permission Reference<a class=\"anchor\" href=\"#appendix-c--permission-reference\" aria-hidden=\"true\">#</a></h2><table><thead><tr><th>Permission</th><th>Category</th><th>Grants</th></tr></thead><tbody><tr><td>View Schedule</td><td>Schedule</td><td>See the grid</td></tr><tr><td>Edit Schedule</td><td>Schedule</td><td>Assign/clear/approve on the grid</td></tr><tr><td>Auto-Scheduler</td><td>Schedule</td><td>Use Auto-Generate / Clear Auto</td></tr><tr><td>Submit Own Requests</td><td>My Requests</td><td>Use the My Requests page</td></tr><tr><td>View All Requests</td><td>Requests</td><td>See &amp; filter everyone's requests</td></tr><tr><td>View Staff</td><td>Staff</td><td>See the staff directory</td></tr><tr><td>Edit Staff</td><td>Staff</td><td>Create/edit/remove staff</td></tr><tr><td>View Statistics</td><td>Statistics</td><td>See equity analytics</td></tr><tr><td>Manage Statistics Views</td><td>Statistics</td><td>Save/share statistics views</td></tr><tr><td>View Settings</td><td>Settings</td><td>Open Settings (read-only)</td></tr><tr><td>Edit Settings</td><td>Settings</td><td>Change settings</td></tr><tr><td>Edit Auto-Generation Priority</td><td>Settings</td><td>Reorder auto-gen priority</td></tr><tr><td>View Users</td><td>Users</td><td>See the users list</td></tr><tr><td>Edit Users</td><td>Users</td><td>Create/edit/disable logins</td></tr><tr><td>View Groups</td><td>Groups</td><td>See groups</td></tr><tr><td>Edit Groups</td><td>Groups</td><td>Create/edit groups</td></tr><tr><td>View User Manual</td><td>Help</td><td>Open the in-app user manual (granted to level-1+ groups by default)</td></tr></tbody></table><p>Default group assignments are in <a href=\"#4-roles--permissions\">§4</a>.</p><hr><p><em>This manual reflects YoSched's current behavior. Some settings note that finer enforcement (e.g., soft/hard pay-period targets) is still being expanded; the UI labels in those areas indicate when a control feeds existing logic versus newer behavior.</em></p></main>\n<a class=\"totop\" href=\"#top\">↑ Top</a>\n</body>\n</html>\n";
